import{_ as e,o,c as t,ae as l}from"./chunks/framework.CRIdhvba.js";const u=JSON.parse('{"title":"C++ 教程 · 第 1 章 语言与环境简介","description":"","frontmatter":{"title":"C++ 教程 · 第 1 章 语言与环境简介"},"headers":[],"relativePath":"tutorials/cpp/index.md","filePath":"tutorials/cpp/index.md"}'),a={name:"tutorials/cpp/index.md"};function r(n,i,s,d,c,p){return o(),t("div",null,[...i[0]||(i[0]=[l('<h1 id="第-1-章-·-c-语言与环境简介" tabindex="-1">第 1 章 · C++ 语言与环境简介 <a class="header-anchor" href="#第-1-章-·-c-语言与环境简介" aria-label="Permalink to &quot;第 1 章 · C++ 语言与环境简介&quot;">​</a></h1><p>C++ 是一门兼具 <strong>高性能</strong> 与 <strong>高抽象能力</strong> 的编程语言，在游戏引擎、高性能服务器、数据库内核、嵌入式等领域都有广泛应用。本教程面向有一定编程基础、希望向「工程级 C++ 开发」迈进的同学。</p><p>在本章中，你将了解：</p><ul><li>C++ 在现代软件栈中的定位</li><li>C++ 标准与编译器生态（GCC/Clang/MSVC 等）</li><li>基础开发环境的搭建方式</li><li>如何在网页中快速体验、调试一段 C++ 代码</li></ul><h2 id="_1-1-c-的典型应用场景" tabindex="-1">1.1 C++ 的典型应用场景 <a class="header-anchor" href="#_1-1-c-的典型应用场景" aria-label="Permalink to &quot;1.1 C++ 的典型应用场景&quot;">​</a></h2><ul><li><strong>系统软件</strong>：操作系统内核、驱动、数据库内核（如 MySQL/InnoDB 的大量核心代码使用 C++ 实现）。</li><li><strong>高性能服务端</strong>：高并发网关、撮合引擎、实时计算等对延迟极度敏感的服务。</li><li><strong>桌面与游戏开发</strong>：游戏引擎（Unreal Engine）、图形渲染、桌面客户端等需要精细控制资源的场景。</li><li><strong>嵌入式与 IoT</strong>：资源受限但又需要一定抽象能力的设备端开发。</li></ul><p>理解这些场景，有助于你在后续学习中建立「为何而学」的直觉。</p><h2 id="_1-2-本地开发环境概览" tabindex="-1">1.2 本地开发环境概览 <a class="header-anchor" href="#_1-2-本地开发环境概览" aria-label="Permalink to &quot;1.2 本地开发环境概览&quot;">​</a></h2><p>日常工程开发中，你通常会在本地安装：</p><ul><li>一个 C++ 编译器：如 <code>g++</code>（GCC）、<code>clang++</code> 或 MSVC。</li><li>一个熟悉的编辑器或 IDE：如 VS Code、CLion、Visual Studio 等。</li><li>构建工具：如 CMake、Ninja 或各类工程脚手架。</li></ul><p>本教程后续章节会围绕「如何编写现代 C++ 代码」展开，而不是停留在语法罗列上。</p><h2 id="_1-3-网页中的-c-在线调试体验" tabindex="-1">1.3 网页中的 C++ 在线调试体验 <a class="header-anchor" href="#_1-3-网页中的-c-在线调试体验" aria-label="Permalink to &quot;1.3 网页中的 C++ 在线调试体验&quot;">​</a></h2><p>为了方便你 <strong>快速尝试一小段 C++ 代码</strong>，我们在页面中嵌入了在线 C++ 运行环境。你可以：</p><ol><li>修改示例代码；</li><li>点击「运行」或「调试」按钮；</li><li>在右侧/下方的输出区域观察程序行为。</li></ol><blockquote><p>说明：实际编译/运行由第三方在线编译服务完成，因此首次加载可能稍慢，且需保持网络可用。</p></blockquote><div style="border:1px solid var(--vp-c-divider);border-radius:8px;overflow:hidden;margin-top:16px;"><iframe src="https://c.runoob.com/compile/11/" style="width:100%;min-height:520px;border:none;" loading="lazy" title="在线 C++ 调试示例（中国区）"></iframe></div><p>你可以将上方示例中的 <code>std::cout</code> 输出、循环、条件分支等逐步修改，并通过在线环境观察行为变化，这就是最简单直接的「调试」方式之一。</p>',17)])])}const h=e(a,[["render",r]]);export{u as __pageData,h as default};
